'use client';

import * as React from 'react';
import {
  Box, Container, Stack, Typography, TextField, InputAdornment,
  Tabs, Tab, Card, CardContent, CardActions, Button, Chip, IconButton,
  Divider, List, ListItem, ListItemText, ListItemSecondaryAction,
  Drawer, Dialog, DialogTitle, DialogContent, DialogActions, MenuItem, Select,
} from '@mui/material';
import SearchRoundedIcon from '@mui/icons-material/SearchRounded';
import AddRoundedIcon from '@mui/icons-material/AddRounded';
import RemoveRoundedIcon from '@mui/icons-material/RemoveRounded';
import DeleteRoundedIcon from '@mui/icons-material/DeleteRounded';
import ReceiptLongRoundedIcon from '@mui/icons-material/ReceiptLongRounded';
import LocalOfferRoundedIcon from '@mui/icons-material/LocalOfferRounded';
import ShoppingBagRoundedIcon from '@mui/icons-material/ShoppingBagRounded';
import LayersRoundedIcon from '@mui/icons-material/LayersRounded';
import CreditCardRoundedIcon from '@mui/icons-material/CreditCardRounded';
import PrintRoundedIcon from '@mui/icons-material/PrintRounded';
import ImageRoundedIcon from '@mui/icons-material/ImageRounded';
import StickyNote2RoundedIcon from '@mui/icons-material/StickyNote2Rounded';

type Variant = { name: string; price: number; note?: string };
type Product = {
  id: string;
  name: string;
  cover: string;
  tint: string;
  badge?: 'NEW' | 'HIT';
  category: 'นามบัตร' | 'Postcard' | 'Print A3/A4' | 'Photo' | 'Sticker Laser';
  variants: Variant[];
};

type CartItem = {
  key: string;
  productId: string;
  name: string;
  variant: string;
  unitPrice: number;
  qty: number;
};

const money = (n: number) =>
  new Intl.NumberFormat('th-TH', {
    style: 'currency',
    currency: 'THB',
    maximumFractionDigits: 0,
  }).format(n);

const CATALOG: Product[] = [
  {
    id: 'bc_55x90',
    name: 'นามบัตร 5.5×9 ซม.',
    cover: '💳',
    tint: '#e8f0ff',
    category: 'นามบัตร',
    variants: [
      { name: '250g ด้าน – 1 ด้าน', price: 300 },
      { name: '250g ด้าน – 2 ด้าน', price: 500 },
      { name: '260g เงา – 1 ด้าน', price: 300 },
      { name: '260g เงา – 2 ด้าน', price: 500 },
      { name: '300g เงา – 1 ด้าน', price: 350 },
      { name: '300g เงา – 2 ด้าน', price: 550 },
      { name: '180g ด้าน – 1 ด้าน', price: 250 },
      { name: '180g ด้าน – 2 ด้าน', price: 400 },
      { name: 'PVC ด้าน 200MC – 1 ด้าน', price: 500 },
      { name: 'PVC ด้าน 200MC – 2 ด้าน', price: 700 },
    ],
  },
  {
    id: 'post_4x6',
    name: 'Postcard 4×6"',
    cover: '🖼️',
    tint: '#fff0f5',
    badge: 'HIT',
    category: 'Postcard',
    variants: [
      { name: '250/260เงา/300 ด้าน – 1 หน้า', price: 25, note: 'ขั้นต่ำ 4 รูป' },
      { name: '250/260เงา/300 ด้าน – 2 หน้า', price: 35, note: 'ขั้นต่ำ 4 รูป' },
    ],
  },
  {
    id: 'post_5x7',
    name: 'Postcard 5×7"',
    cover: '📮',
    tint: '#f3f7e9',
    category: 'Postcard',
    variants: [
      { name: 'ทุกชนิดกระดาษ – 1 หน้า', price: 35, note: 'ขั้นต่ำ 2 รูป' },
      { name: 'ทุกชนิดกระดาษ – 2 หน้า', price: 45, note: 'ขั้นต่ำ 2 รูป' },
    ],
  },
  {
    id: 'print_a4',
    name: 'Print A4',
    cover: '🖨️',
    tint: '#eef9ff',
    category: 'Print A3/A4',
    variants: [
      { name: '250/260เงา – 1 หน้า', price: 45 },
      { name: '250/260เงา – 2 หน้า', price: 90 },
      { name: '300g ด้าน – 1 หน้า', price: 55 },
      { name: '300g ด้าน – 2 หน้า', price: 100 },
      { name: '180g – 1 หน้า', price: 25 },
      { name: '180g – 2 หน้า', price: 40 },
    ],
  },
  {
    id: 'print_a3',
    name: 'Print A3',
    cover: '🖨️',
    tint: '#eefcff',
    category: 'Print A3/A4',
    variants: [
      { name: '250/260เงา – 1 หน้า', price: 90 },
      { name: '250/260เงา – 2 หน้า', price: 150 },
      { name: '300g ด้าน – 1 หน้า', price: 110 },
      { name: '300g ด้าน – 2 หน้า', price: 180 },
      { name: '180g – 1 หน้า', price: 55 },
      { name: '180g – 2 หน้า', price: 120 },
    ],
  },
  {
    id: 'photo_passport',
    name: 'รูปติดบัตร / Passport',
    cover: '🪪',
    tint: '#f4f6ff',
    category: 'Photo',
    variants: [{ name: 'ชุด 12 ใบ', price: 90 }],
  },
  {
    id: 'laser_a3plus',
    name: 'Sticker Laser A3+',
    cover: '🧾',
    tint: '#f7f1ff',
    badge: 'NEW',
    category: 'Sticker Laser',
    variants: [
      { name: 'PP ขาวเงา – ชุด 7 A3+', price: 550 },
      { name: 'PP ขาวด้าน – ชุด 7 A3+', price: 550 },
      { name: 'Paper ขาวเงา – ชุด 7 A3+', price: 550 },
      { name: 'Paper ขาวด้าน – ชุด 7 A3+', price: 550 },
      { name: 'ใส (Clear) – ชุด 7 A3+', price: 550 },
    ],
  },
];

export default function SellPage() {
  const [tab, setTab] = React.useState<Product['category']>('นามบัตร');
  const [q, setQ] = React.useState('');
  const [cart, setCart] = React.useState<CartItem[]>([]);
  const [drawer, setDrawer] = React.useState(false);
  const [variantDlg, setVariantDlg] = React.useState<{ p: Product | null; v: string }>({ p: null, v: '' });

  const totalQty = cart.reduce((s, i) => s + i.qty, 0);
  const totalPrice = cart.reduce((s, i) => s + i.qty * i.unitPrice, 0);

  const filtered = React.useMemo(
    () =>
      CATALOG.filter((p) => p.category === tab)
        .filter((p) => p.name.toLowerCase().includes(q.toLowerCase())),
    [tab, q]
  );

  const add = (p: Product, vName: string) => {
    const v = p.variants.find((vv) => vv.name === vName);
    if (!v) return;
    const key = `${p.id}::${encodeURIComponent(v.name)}`;
    setCart((prev) => {
      const ex = prev.find((i) => i.key === key);
      if (ex) return prev.map((i) => (i.key === key ? { ...i, qty: i.qty + 1 } : i));
      return [...prev, { key, productId: p.id, name: p.name, variant: v.name, unitPrice: v.price, qty: 1 }];
    });
  };

  const subQty = (key: string) =>
    setCart((prev) => prev.map((i) => (i.key === key ? { ...i, qty: i.qty - 1 } : i)).filter((i) => i.qty > 0));

  const addQty = (key: string) =>
    setCart((prev) => prev.map((i) => (i.key === key ? { ...i, qty: i.qty + 1 } : i)));

  const removeItem = (key: string) => setCart((prev) => prev.filter((i) => i.key !== key));

  const quickAdd = (p: Product) => {
    if (p.variants.length === 1) add(p, p.variants[0].name);
    else setVariantDlg({ p, v: p.variants[0].name });
  };

  return (
    <Box sx={{ minHeight: '100dvh' }}>
      <Container maxWidth="xl" sx={{ py: 2 }}>
        {/* Header */}
        <Stack direction="row" alignItems="center" spacing={1} sx={{ mb: 2 }}>
          <ReceiptLongRoundedIcon />
          <Typography variant="h5" fontWeight={800}>หน้าขาย (POS)</Typography>
          
          <Box sx={{ flex: 1 }} />
          <TextField
            size="small"
            placeholder="ค้นหา…"
            value={q}
            onChange={(e) => setQ(e.target.value)}
            InputProps={{ startAdornment: <InputAdornment position="start"><SearchRoundedIcon /></InputAdornment> }}
          />
          <Button
            startIcon={<ShoppingBagRoundedIcon />}
            variant="contained"
            onClick={() => setDrawer(true)}
            sx={{ ml: 1 }}
          >
            ตะกร้า {totalQty ? `(${totalQty})` : ''}
          </Button>
        </Stack>

        {/* Layout: Left menu (flex wrap) + Right summary (sticky) */}
        <Box
          sx={{
            display: 'flex',
            gap: 2,
          }}
        >
          {/* LEFT: product area */}
          <Box sx={{ flex: 1, minWidth: 0 }}>
            {/* category tabs */}
            <Tabs
              value={tab}
              onChange={(_, v) => setTab(v)}
              variant="scrollable"
              allowScrollButtonsMobile
              sx={{
                mb: 2,
                '& .MuiTabs-indicator': { height: 3 },
              }}
            >
              <Tab value="นามบัตร" icon={<CreditCardRoundedIcon />} iconPosition="start" label="นามบัตร" />
              <Tab value="Postcard" icon={<ImageRoundedIcon />} iconPosition="start" label="Postcard" />
              <Tab value="Print A3/A4" icon={<PrintRoundedIcon />} iconPosition="start" label="Print A3/A4" />
              <Tab value="Photo" icon={<ImageRoundedIcon />} iconPosition="start" label="Photo" />
              <Tab value="Sticker Laser" icon={<StickyNote2RoundedIcon />} iconPosition="start" label="Sticker Laser" />
            </Tabs>

            {/* cards list (NO Grid) */}
            <Box
              sx={{
                display: 'flex',
                flexWrap: 'wrap',
                gap: 16 / 8, // 2
              }}
            >
              {filtered.map((p) => (
                <Card
                  key={p.id}
                  variant="outlined"
                  sx={{
                    width: { xs: 'calc(50% - 8px)', sm: 260, md: 280 },
                    borderRadius: 3,
                    overflow: 'hidden',
                    backdropFilter: 'blur(4px)',
                    boxShadow: '0 6px 24px rgba(0,0,0,.06)',
                    '&:hover': { boxShadow: '0 10px 28px rgba(0,0,0,.10)', transform: 'translateY(-1px)' },
                    transition: 'all .2s',
                  }}
                >
                  <Box
                    sx={{
                      height: 120,
                      bgcolor: p.tint,
                      display: 'grid',
                      placeItems: 'center',
                      fontSize: 56,
                    }}
                  >
                    {p.cover}
                  </Box>
                  <CardContent sx={{ pb: 0.5 }}>
                    <Stack direction="row" alignItems="center">
                      <Typography sx={{ fontWeight: 700, flex: 1 }} noWrap>{p.name}</Typography>
                      {p.badge && <Chip size="small" label={p.badge} color={p.badge === 'NEW' ? 'secondary' : 'primary'} />}
                    </Stack>
                    <Typography variant="body2" color="text.secondary">
                      {p.variants.length > 1 ? `${money(p.variants[0].price)}+` : money(p.variants[0].price)}
                    </Typography>
                  </CardContent>
                  <CardActions sx={{ p: 1.5, pt: 0.5 }}>
                    <Button fullWidth variant="contained" onClick={() => quickAdd(p)}>
                      เพิ่มลงรายการ
                    </Button>
                  </CardActions>
                </Card>
              ))}
            </Box>
          </Box>

          {/* RIGHT: summary */}
          <Box
            sx={{
              width: { xs: 320, md: 380 },
              position: 'sticky',
              top: 16,
              alignSelf: 'flex-start',
              borderRadius: 3,
              p: 2,
              background: 'linear-gradient(180deg,rgba(255,255,255,.65),rgba(255,255,255,.9))',
              border: '1px solid',
              borderColor: 'divider',
              boxShadow: '0 8px 36px rgba(0,0,0,.08)',
            }}
          >
            <Stack direction="row" alignItems="center" spacing={1} sx={{ mb: 1 }}>
              <LayersRoundedIcon />
              <Typography variant="h6" fontWeight={800}>รายการที่เลือก</Typography>
              <Chip label={`${totalQty} รายการ`} size="small" sx={{ ml: 'auto' }} />
            </Stack>
            <Divider sx={{ mb: 1 }} />

            <List dense sx={{ maxHeight: 360, overflowY: 'auto' }}>
                {cart.map((i) => (
                <ListItem
                    key={i.key}
                    sx={{ py: 1, pr: 7 }}
                    secondaryAction={
                        <Stack direction="row" alignItems="center" spacing={1} mt={6}>
                        <IconButton size="small" onClick={() => subQty(i.key)}><RemoveRoundedIcon /></IconButton>
                        <Typography minWidth={20} textAlign="center">{i.qty}</Typography>
                        <IconButton size="small" onClick={() => addQty(i.key)}><AddRoundedIcon /></IconButton>
                        <IconButton size="small" onClick={() => removeItem(i.key)}><DeleteRoundedIcon /></IconButton>
                        </Stack>
                    }
                    >
                    <ListItemText
                        primary={
                        <Stack direction="row" alignItems="center" spacing={1}>
                            <Typography fontWeight={700}>{i.name}</Typography>
                            <Chip
                            size="small"
                            label={i.variant}
                            variant="outlined"
                            sx={{
                                maxWidth: 180,
                                '& .MuiChip-label': { overflow: 'hidden', textOverflow: 'ellipsis' },
                            }}
                            />
                        </Stack>
                        }
                        secondary={money(i.unitPrice)}
                    />
                    </ListItem>
                ))}
                </List>


            <Divider sx={{ my: 1.5 }} />

            <Stack spacing={2.5}>
              <Stack direction="row">
                <Typography sx={{ flex: 1, color: 'text.secondary' }}>ยอดรวม</Typography>
                <Typography fontWeight={800}>{money(totalPrice)}</Typography>
              </Stack>

              <TextField
                size="small"
                placeholder="ส่วนลด/โค้ด"
                InputProps={{ startAdornment: <InputAdornment position="start"><LocalOfferRoundedIcon /></InputAdornment> }}
              />

              <Button
                variant="contained"
                color="success"
                startIcon={<ShoppingBagRoundedIcon />}
                disabled={cart.length === 0}
                onClick={() => setDrawer(true)}
              >
                ชำระเงิน
              </Button>
            </Stack>
          </Box>
        </Box>
      </Container>

      {/* เลื่อนมาดูตะกร้าเต็มจอ (มือถือ/Tablet) */}
      <Drawer anchor="right" open={drawer} onClose={() => setDrawer(false)}>
        <Box sx={{ width: { xs: 320, sm: 420 }, p: 2 }}>
          <Typography variant="h6" fontWeight={800} sx={{ mb: 1 }}>สรุปรายการ</Typography>
          <Divider />
          <List dense>
            {cart.map((i) => (
              <ListItem key={i.key} sx={{ py: 1 }}>
                <ListItemText
                  primary={`${i.name} — ${i.variant}`}
                  secondary={`${money(i.unitPrice)} × ${i.qty}`}
                />
                <Typography fontWeight={700}>{money(i.unitPrice * i.qty)}</Typography>
              </ListItem>
            ))}
          </List>
          <Divider />
          <Stack direction="row" sx={{ mt: 1 }}>
            <Typography sx={{ flex: 1 }}>ยอดรวม</Typography>
            <Typography fontWeight={800}>{money(totalPrice)}</Typography>
          </Stack>
          <Button
            fullWidth
            sx={{ mt: 2 }}
            variant="contained"
            color="success"
            onClick={() => alert('ไปขั้นตอนชำระเงิน (demo)')}
          >
            ดำเนินการชำระเงิน
          </Button>
        </Box>
      </Drawer>

      {/* เลือก Variant (กรณีหลายราคา) */}
      <Dialog open={!!variantDlg.p} onClose={() => setVariantDlg({ p: null, v: '' })} fullWidth>
        <DialogTitle fontWeight={800}>{variantDlg.p?.name}</DialogTitle>
        <DialogContent>
          <Select
            fullWidth size="small"
            value={variantDlg.v}
            onChange={(e) => setVariantDlg((s) => ({ ...s, v: e.target.value as string }))}
          >
            {variantDlg.p?.variants.map((v) => (
              <MenuItem key={v.name} value={v.name}>
                {v.name} — {money(v.price)} {v.note ? `(${v.note})` : ''}
              </MenuItem>
            ))}
          </Select>
        </DialogContent>
        <DialogActions>
          <Button onClick={() => setVariantDlg({ p: null, v: '' })}>ยกเลิก</Button>
          <Button
            variant="contained"
            onClick={() => {
              if (!variantDlg.p || !variantDlg.v) return;
              add(variantDlg.p, variantDlg.v);
              setVariantDlg({ p: null, v: '' });
            }}
          >
            เพิ่มลงรายการ
          </Button>
        </DialogActions>
      </Dialog>
    </Box>
  );
}